$cssPath = "css/common.css"
$cssContent = [System.IO.File]::ReadAllText($cssPath)
$cssContent = $cssContent -replace "(?s)\.iframe-tour-card h3 \{.*?\n\}", ".iframe-tour-card h3 {`n    margin: 0;`n    padding: 0;`n    font-size: 1.35rem;`n    color: var(--white);`n    background-color: transparent;`n    text-shadow: 0 2px 5px rgba(0,0,0,0.8);`n    font-weight: 600;`n    display: block;`n    min-height: auto;`n}"
$cssContent = $cssContent -replace "(?s)\.iframe-tour-card p \{.*?\n\}", ".iframe-tour-card p {`n    margin-top: 0.5rem;`n    margin-bottom: 0;`n    color: rgba(255, 255, 255, 0.95);`n    text-shadow: 0 1px 4px rgba(0,0,0,0.8);`n    font-size: 0.95rem;`n    line-height: 1.5;`n}"
$cssContent = $cssContent -replace "(?s)\.card-maximize-btn \{.*?\n\}", ".card-maximize-btn {`n    position: absolute;`n    bottom: 20px;`n    right: 20px;`n    left: auto;`n    background-color: rgba(255, 255, 255, 0.95);`n    color: var(--primary);`n    border: none;`n    border-radius: 50%;`n    width: 44px;`n    height: 44px;`n    display: flex;`n    align-items: center;`n    justify-content: center;`n    cursor: pointer;`n    z-index: 6;`n    transition: all 0.3s ease;`n    box-shadow: 0 4px 10px rgba(0,0,0,0.25);`n    opacity: 0.9;`n}"
$cssContent = $cssContent -replace "(?s)\.card-maximize-btn:hover \{.*?\n\}", ".card-maximize-btn:hover {`n    background-color: var(--white);`n    transform: scale(1.1);`n    opacity: 1;`n    box-shadow: 0 6px 14px rgba(0,0,0,0.35);`n}"
$cssContent = $cssContent -replace "(?s)\.iframe-tour-card \{.*?\n\}", ".iframe-tour-card {`n    background-color: var(--white);`n    border-radius: 12px;`n    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);`n    overflow: hidden;`n    position: relative;`n    transition: transform 0.3s ease, box-shadow 0.3s ease;`n    width: 100%;`n    height: 100%;`n}"
[System.IO.File]::WriteAllText($cssPath, $cssContent)
